#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int factorial(int n) {
    int result = 1;
    for (int i = 2; i <= n; i++) {
        result = (result * i) % MOD;
    }
    return result;
}

int is_connected(int* permutation, int n, int** edges, int m) {
    for (int i = 0; i < n - 1; i++) {
        int found = 0;
        for (int j = 0; j < m; j++) {
            if ((permutation[i] == edges[j][0] && permutation[i + 1] == edges[j][1]) || (permutation[i] == edges[j][1] && permutation[i + 1] == edges[j][0])) {
                found = 1;
                break;
            }
        }
        if (!found) return 0;
    }
    return 1;
}

int main() {
    int t;
    scanf("%d", &t);
