import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int m = scanner.nextInt();
            int[][] edges = new int[m][2];
            for (int i = 0; i < m; i++) {
                edges[i][0] = scanner.nextInt();
                edges[i][1] = scanner.nextInt();
            }
            int[] permutation = new int[n];
            for (int i = 0; i < n; i++) permutation[i] = i + 1;
            int count = 0;
            do {
                if (isConnected(permutation, n, edges, m)) count = (count + 1) % MOD;
            } while (nextPermutation(permutation));
            System.out.println(count);
        }
    }
    public static boolean isConnected(int[] permutation, int n, int[][] edges, int m) {
        for (int i = 0; i < n - 1; i++) {
            boolean found = false;
            for (int j = 0; j < m; j++) {
                if ((permutation[i] == edges[j][0] && permutation[i + 1] == edges[j][1]) || (permutation[i] == edges[j][1] && permutation[i + 1] == edges[j][0])) {
                    found = true;
                    break;
                }
            }
            if (!found) return false;
        }
        return true;
    }
    public static boolean nextPermutation(int[] permutation) {
        int i = permutation.length - 2;
        while (i >= 0 && permutation[i] >= permutation[i + 1]) i--;
        if (i < 0) return false;
        int j = permutation.length - 1;
        while (j > i && permutation[j] <= permutation[i]) j--;
        int temp = permutation[i];
        permutation[i] = permutation[j];
        permutation[j] = temp;
        int left = i + 1;
        int right = permutation.length - 1;
        while (left < right) {
            temp = permutation[left];
            permutation[left] = permutation[right];
            permutation[right] = temp;
            left++;
            right--;
        }
        return true;
    }
}

