import itertools
MOD = 1000000007

def is_connected(permutation, n, edges, m):
    for i in range(n - 1):
        found = False
        for j in range(m):
            if (permutation[i] == edges[j][0] and permutation[i + 1] == edges[j][1]) or (permutation[i] == edges[j][1] and permutation[i + 1] == edges[j][0]):
