    for _ in range(t):
        n, m = map(int, input().split())
        edges = [list(map(int, input().split())) for _ in range(m)]
        permutation = list(range(1, n + 1))
        count = 0
        for p in itertools.permutations(permutation):
            if is_connected(p, n, edges, m): count = (count + 1) % MOD
        print(count)
